import React, { useState, useEffect } from "react";
import "./Placement.css";

export default function Placement() {
  const user = JSON.parse(localStorage.getItem("loggedInUser"));
  const [placements, setPlacements] = useState(
    JSON.parse(localStorage.getItem("placements")) || []
  );

  const [formData, setFormData] = useState({
    role: "",
    company: "",
    package: "",
    location: "",
    applyLink: "",
  });

  const handleAdd = () => {
    const updated = [...placements, formData];
    localStorage.setItem("placements", JSON.stringify(updated));
    setPlacements(updated);
    setFormData({ role: "", company: "", package: "", location: "", applyLink: "" });
  };

  const handleDelete = (index) => {
    const updated = placements.filter((_, i) => i !== index);
    localStorage.setItem("placements", JSON.stringify(updated));
    setPlacements(updated);
  };

  const handleEdit = (index) => {
    setFormData(placements[index]);
    handleDelete(index);
  };

  const isStudent = user.role === "Student";
  const isHR = user.role === "HR";
  const isAdmin = user.role === "Admin";

  return (
    <div className="placement-container">
      <h2>Placement Opportunities</h2>

      {!isStudent && (
        <div className="form-section">
          <input
            type="text"
            placeholder="Role"
            value={formData.role}
            onChange={(e) => setFormData({ ...formData, role: e.target.value })}
          />
          <input
            type="text"
            placeholder="Company"
            value={formData.company}
            onChange={(e) => setFormData({ ...formData, company: e.target.value })}
          />
          <input
            type="text"
            placeholder="Package"
            value={formData.package}
            onChange={(e) => setFormData({ ...formData, package: e.target.value })}
          />
          <input
            type="text"
            placeholder="Location"
            value={formData.location}
            onChange={(e) => setFormData({ ...formData, location: e.target.value })}
          />
          <input
            type="text"
            placeholder="Apply Link"
            value={formData.applyLink}
            onChange={(e) => setFormData({ ...formData, applyLink: e.target.value })}
          />
          <button onClick={handleAdd}>Add Placement</button>
        </div>
      )}

      <div className="placement-list">
        {placements.length === 0 ? (
          <p>No placements available.</p>
        ) : (
          placements.map((item, index) => (
            <div key={index} className="placement-card">
              <h3>{item.role}</h3>
              <p><strong>Company:</strong> {item.company}</p>
              <p><strong>Package:</strong> {item.package}</p>
              <p><strong>Location:</strong> {item.location}</p>
              <a href={item.applyLink} target="_blank" rel="noreferrer">Apply</a>

              {isAdmin && (
                <div className="action-buttons">
                  <button onClick={() => handleEdit(index)}>Edit</button>
                  <button onClick={() => handleDelete(index)}>Delete</button>
                </div>
              )}
            </div>
          ))
        )}
      </div>
    </div>
  );
}
